+//! Integration tests for CLIENT PAUSE / CLIENT UNPAUSE behavior.
+
+use fr_protocol::RespFrame;
+use fr_runtime::Runtime;
+
+fn command(parts: &[&[u8]]) -> RespFrame {
+    RespFrame::Array(Some(
+        parts
