+#[test]
+fn client_pause_commands_execute_after_expiry() {
+    let mut rt = Runtime::default_strict();
+
+    // Set a key first
+    rt.execute_frame(command(&[b"SET", b"pause_key", b"before"]), 0);
+
+    // Pause for 2000ms
