+    // Execute SET after pause expires
+    rt.execute_frame(command(&[b"SET", b"pause_key", b"after"]), 3001);
+    let val = rt.execute_frame(command(&[b"GET", b"pause_key"]), 3002);
+    assert_eq!(val, RespFrame::BulkString(Some(b"after".to_vec())));
+}

