+
+    dump_restore_roundtrip(&mut rt, b"int_key", 1);
+
+    let val = rt.execute_frame(command(&[b"GET", b"int_key"]), 2);
+    assert_eq!(val, RespFrame::BulkString(Some(b"42".to_vec())));
+}
